import Redis from "ioredis";

/**
 * Sliding‑window rate limiter backed by Redis.
 *
 * The window slides from the current time (obtained from Redis TIME) back
 * for `windowSec` seconds. Only timestamps that fall inside the window are
 * kept; any older entries are removed in the same atomic Lua script.
 *
 * @example
 * const limiter = new RateLimiter({ redis: new Redis(), limit: 100, windowSec: 60 });
 * const allowed = await limiter.allow("user:123");
 * const remaining = await limiter.remaining("user:123");
 * const resetAt = await limiter.resetAt("user:123");
 */
export class RateLimiter {
  private readonly redis: Redis;
  private readonly limit: number;
  private readonly windowSec: number;

  /**
   * Lua script that:
   * 1. Removes timestamps older than the sliding window.
   * 2. Counts the remaining timestamps.
   * 3. Returns the count and the oldest timestamp still inside the window.
   *
   * KEYS[1] – the Redis key for the rate‑limit bucket.
   * ARGV[1] – current server time in milliseconds (from Redis TIME).
   * ARGV[2] – window size in milliseconds.
   * ARGV[3] – maximum number of requests allowed.
   *
   * Returns an array: [currentCount, oldestTimestampInWindow (or 0 if empty)]
   */
  private static readonly LUA_SCRIPT = `
local key = KEYS[1]
local now = tonumber(ARGV[1])
local window = tonumber(ARGV[2])
local limit = tonumber(ARGV[3])

-- 1) Prune entries that are older than the sliding window.
redis.call('ZREMRANGEBYSCORE', key, '-inf', now - window)

-- 2) Read the current size of the window (all entries are guaranteed <= now).
local count = redis.call('ZCARD', key)

-- 3) If we are under the limit, add the new request timestamp.
if count < limit then
    redis.call('ZADD', key, now, now .. ':' .. math.random())
    count = count + 1
    -- Set a TTL on the key so Redis reclaims it after the window expires.
    redis.call('EXPIRE', key, math.ceil(window / 1000) + 1)
end

-- 4) Return the count after the decision and the oldest timestamp (if any).
local oldest = redis.call('ZRANGE', key, 0, 0, 'WITHSCORES')
local oldest_ts = 0
if #oldest > 0 then
    oldest_ts = tonumber(oldest[2])
end
return {count, oldest_ts}
`;

  /**
   * SHA cache for the script so subsequent instantiations reuse the same script.
   */
  private scriptSha: string | null = null;

  constructor(opts: { redis: Redis; limit: number; windowSec: number }) {
    if (opts.limit <= 0) throw new Error("limit must be a positive integer");
    if (opts.windowSec <= 0) throw new Error("windowSec must be a positive number");

    this.redis = opts.redis;
    this.limit = opts.limit;
    this.windowSec = opts.windowSec;
  }

  /**
   * Atomically decide whether a request for `key` should be allowed.
   *
   * @param key - The unique identifier for the rate‑limit bucket (e.g. user ID).
   * @returns `true` if the request is allowed, `false` if it is rejected.
   */
  async allow(key: string): Promise<boolean> {
    const [count] = await this.runScript(key);
    // count includes the just‑added request if we were under the limit.
    return count <= this.limit;
  }

  /**
   * Return how many more requests are still allowed for `key`.
   *
   * @param key - The rate‑limit bucket key.
   */
  async remaining(key: string): Promise<number> {
    const [count] = await runScriptWithoutAdd(this.redis, this.scriptSha, key, this.windowSec, this.limit);
    // `count` is the number of entries already inside the window *before* a new request.
    return Math.max(0, this.limit - count);
  }

  /**
   * Return the Unix timestamp (seconds) when the oldest entry in the window will expire,
   * i.e. the moment the request count will drop below the limit.
   *
   * @param key - The rate‑limit bucket key.
   */
  async resetAt(key: string): Promise<number> {
    const [, oldestTs] = await runScriptWithoutAdd(this.redis, this.scriptSha, key, this.windowSec, this.limit);
    if (oldestTs === 0) return 0; // no active entries.
    // The reset moment is when the oldest entry ages out of the window.
    return Math.ceil((oldestTs + this.windowSec * 1000) / 1000);
  }

  /**
   * Internal helper that runs the main Lua script (which may add a new entry).
   */
  private async runScript(key: string): Promise<[number, number]> {
    const nowMs = await this.redis.time().then((t) => Number(t[0]) * 1000 + Math.floor(Number(t[1]) / 1000));
    const windowMs = this.windowSec * 1000;

    const script = RateLimiter.LUA_SCRIPT;
    const sha = await this.getSha();
    const result = (await this.redis.evalsha(
      sha,
      1,
      key,
      nowMs,
      windowMs,
      this.limit
    )) as [number, number];
    return result;
  }

  /** Lazily load the script SHA, caching it for subsequent calls. */
  private async getSha(): Promise<string> {
    if (!this.scriptSha) {
      this.scriptSha = await this.redis.script("LOAD", RateLimiter.LUA_SCRIPT).then(String);
    }
    return this.scriptSha;
  }
}

/**
 * Variant of the script that only prunes and counts (no ZADD).
 * Used by `remaining` and `resetAt` to avoid side‑effects.
 *
 * Returns: [currentCount, oldestTimestampInWindow (or 0 if empty)]
 */
const READ_ONLY_LUA = `
local key = KEYS[1]
local now = tonumber(ARGV[1])
local window = tonumber(ARGV[2])
local limit = tonumber(ARGV[3])

redis.call('ZREMRANGEBYSCORE', key, '-inf', now - window)
local count = redis.call('ZCARD', key)
local oldest = redis.call('ZRANGE', key, 0, 0, 'WITHSCORES')
local oldest_ts = 0
if #oldest > 0 then
    oldest_ts = tonumber(oldest[2])
end
return {count, oldest_ts}
`;

async function runScriptWithoutAdd(
  redis: Redis,
  sha: string | null,
  key: string,
  windowSec: number,
  limit: number
): Promise<[number, number]> {
  const nowMs = await redis.time().then((t) => Number(t[0]) * 1000 + Math.floor(Number(t[1]) / 1000));
  const windowMs = windowSec * 1000;

  // Load the read‑only script once.
  const scriptSha = sha ?? await redis.script("LOAD", READ_ONLY_LUA).then(String);
  const result = (await redis.evalsha(
    scriptSha,
    1,
    key,
    nowMs,
    windowMs,
    limit
  )) as [number, number];
  return result;
}
```

---

**Correctness argument (4 sentences):**

The Lua script atomically removes all timestamps older than `now – window` via `ZREMRANGEBYSCORE` before counting, guaranteeing that only entries inside the sliding window are considered; because the script runs as a single atomic unit, no concurrent script can interleave between the prune and the count, so the count is always consistent with the prune. The `ZCARD` after the prune gives the exact number of requests currently inside the window, and the conditional `ZADD` is performed only when `count < limit`, which means the request is admitted exactly when a slot is available and rejected otherwise, preserving the limit invariant. The `ZRANGE … WITHSCORES` at the end reads the oldest timestamp still inside the window in the same atomic execution, so `resetAt` is derived from a value that is guaranteed not to change until the next script invocation. Finally, the `EXPIRE` command sets a TTL slightly longer than the window, ensuring that Redis automatically discards the entire sorted set after it can no longer contain any valid entries, preventing unbounded memory growth.

