/* json_extract_int.c
 *
 * A single‑pass, zero‑allocation JSON integer extractor.
 * Only the public API is exposed; all helpers are static.
 *
 * API
 *   int json_extract_int(const char *json, const char *path, int64_t *out);
 *
 * Returns 0 on success and writes the int64 value to *out.
 * Returns non‑zero on any error (malformed JSON, type mismatch,
 * out‑of‑range, missing key/index, etc.).
 *
 * Supported path syntax
 *   ""                – selects the root value (must be an integer)
 *   ".key"             – selects member "key" of the current object
 *   "key.sub"          – equivalent to .key.sub
 *   "[n]"              – selects element n of the current array
 *   ".key[n].sub"      – arbitrary mixture of the above
 *
 * Constraints
 *   1. Single‑pass over the JSON – we walk the token stream only once.
 *   2. Rejects malformed JSON (unterminated strings, unbalanced brackets,
 *      invalid escapes, leading zeros, etc.).
 *   3. Rejects numbers that overflow int64 or that have a fractional part.
 *   4. No heap allocation – everything lives on the stack.
 *   5. No external libraries – pure C99 + <string.h>.
 *   6. No reading past the terminating '\0' of the input string.
 *
 * Argument for not reading past the null terminator
 * ---------------------------------------------------
 * The parser never performs a blind advance (e.g. "json++") without first
 * checking that the current character is not '\0'.  Every state machine
 * that consumes a token (string, number, literal) checks for the
 * terminating character *before* advancing past it:
 *
 *   • String parsing stops when a '"' or '\0' is encountered.
 *   • Number parsing stops when a non‑digit, non‑sign, non‑dot,
 *     non‑exponent character is seen – which is never '\0' because
 *     a lone '\0' cannot be part of a numeric token.
 *   • Literal parsing (true/false/null) stops after the required
 *     characters have been verified; a '\0' before the literal is
 *     complete is treated as an error.
 *
 * Consequently, if the input string ends prematurely (i.e. the JSON is
 * truncated), the parser returns a non‑zero error code rather than
 * reading beyond the buffer.
 */

#include <stdint.h>
#include <stddef.h>  /* for size_t */
#include <string.h>
#include <ctype.h>

/* ------------------------------------------------------------------ */
/* Internal error codes (private to the implementation)                */

typedef enum {
    JERR_OK = 0,
    JERR_END_OF_INPUT,      /* unexpected end of JSON */
    JERR_UNEXPECTED_CHAR,   /* malformed token or unexpected character */
    JERR_STRING_EOF,       /* unterminated string */
    JERR_INVALID_ESCAPE,     /* invalid escape sequence in string */
    JERR_INVALID_UTF8,      /* malformed UTF‑8 in string */
    JERR_NUMBER_OVERFLOW,   /* integer does not fit in int64_t */
    JERR_NUMBER_FRACTIONAL, /* number has a fractional part or exponent */
    JERR_NUMBER_LEADING_ZEROS, /* e.g. 00, 007 */
    JERR_TYPE_MISMATCH,     /* value is not an integer */
    JERR_PATH_MALFORMED,    /* path syntax error */
    JERR_PATH_NOT_FOUND,    /* key / index not present */
    JERR_BRACKET_MISMATCH,  /* unbalanced brackets / braces */
} JsonErr;

/* ------------------------------------------------------------------ */
/* Forward declarations of static helpers                              */

static const char *skip_ws(const char *p);
static int  parse_literal(const char **p, const char *lit);
static int  parse_string(const char **p, char *buf, size_t bufsz, int *len);
static int  parse_number(const char **p, int64_t *out);
static int  parse_value(const char **p, int64_t *out);
static int  follow_path(const char *json, const char *path, int64_t *out);

/* ------------------------------------------------------------------ */
/* Public API                                                          */

int json_extract_int(const char *json, const char *path, int64_t *out)
{
    if (!json || !out)
        return -1;

    /* An empty JSON document is the only valid input that starts with
     * whitespace or a closing brace – anything else is an error. */
    if (*json == '\0')
        return JERR_END_OF_INPUT;

    return follow_path(json, path, out);
}

/* ------------------------------------------------------------------ */
/* Helper: skip whitespace (ASCII 0x20, 0x09, 0x0A, 0x0D)               */

static const char *skip_ws(const char *p)
{
    while (*p == ' ' || *p == '\t' || *p == '\n' || *p == '\r')
        ++p;
    return p;
}

/* ------------------------------------------------------------------ */
/* Helper: parse a JSON literal (true / false / null)                   */

static int parse_literal(const char **p, const char *lit)
{
    const char *q = *p;
    size_t len = strlen(lit);
    if (strncmp(q, lit, len) != 0)
        return JERR_UNEXPECTED_CHAR;
    if (q[len] != '\0' && !isspace((unsigned char)q[len]) &&
        q[len] != ',' && q[len] != ']' && q[len] != '}') {
        /* The literal is a prefix of something longer (e.g. "trueX") */
        return JERR_UNEXPECTED_CHAR;
    }
    *p = q + len;
    return JERR_OK;
}

/* ------------------------------------------------------------------ */
/* Helper: parse a JSON string into a caller‑provided buffer.
 *   buf   – output buffer (may be NULL to count characters only)
 *   bufsz – size of buf (0 if buf is NULL)
 *   len   – receives the number of characters written (excluding '\0')
 *
 * Returns 0 on success, non‑zero on error.
 *
 * Escapes handled: \" \\ \/ \b \f \n \r \t \uXXXX
 * UTF‑8 handling: surrogate pairs are combined into a single multi‑byte
 *                sequence (up to 4 bytes) stored in the buffer.
 */

static int parse_string(const char **p, char *buf, size_t bufsz, int *len)
{
    const char *q = *p;
    int written = 0;

    if (*q != '"')
        return JERR_UNEXPECTED_CHAR;
    ++q;

    while (*q != '"' && *q != '\0') {
        if (*q == '\\') {
            ++q;
            if (*q == '\0')
                return JERR_STRING_EOF;
            switch (*q) {
            case '"': case '\\': case '/':
                if (written < (int)bufsz) buf[written] = *q;
                ++written; ++q; break;
            case 'b':
                if (written < (int)bufsz) buf[written] = '\b';
                ++written; ++q; break;
            case 'f':
                if (written < (int)bufsz) buf[written] = '\f';
                ++written; ++q; break;
            case 'n':
                if (written < (int)bufsz) buf[written] = '\n';
                ++written; ++q; break;
            case 'r':
                if (written < (int)bufsz) buf[written] = '\r';
                ++written; ++q; break;
            case 't':
                if (written < (int)bufsz) buf[written] = '\t';
                ++written; ++q; break;
            case 'u': {
                unsigned i;
                uint32_t codepoint = 0;
                ++q; /* skip 'u' */
                for (i = 0; i < 4; ++i) {
                    char h = *q;
                    unsigned digit;
                    if ('0' <= h && h <= '9')
                        digit = (unsigned)(h - '0');
                    else if ('a' <= h && h <= 'f')
                        digit = (unsigned)(h - 'a' + 10);
                    else if ('A' <= h && h <= 'F')
                        digit = (unsigned)(h - 'A' + 10);
                    else
                        return JERR_INVALID_UTF8; /* invalid hex */
                    codepoint = (codepoint << 4) | digit;
                    ++q;
                }
                /* Encode codepoint as UTF‑8 */
                if (codepoint <= 0x7F) {
                    if (written < (int)bufsz) buf[written] = (char)codepoint;
                    ++written;
                } else if (codepoint <= 0x7FF) {
                    if (written + 1 < (int)bufsz) {
                        buf[written]     = (char)(0xC0 | ((codepoint >> 6) & 0x1F));
                        buf[written + 1] = (char)(0x80 | ( codepoint       & 0x3F));
                    }
                    written += 2;
                } else if (codepoint <= 0xFFFF) {
                    if (written + 2 < (int)bufsz) {
                        buf[written]     = (char)(0xE0 | ((codepoint >> 12) & 0x0F));
                        buf[written + 1] = (char)(0x80 | ((codepoint >>  6) & 0x3F));
                        buf[written + 2] = (char)(0x80 | ( codepoint        & 0x3F));
                    }
                    written += 3;
                } else { /* codepoint <= 0x10FFFF */
                    if (written + 3 < (int)bufsz) {
                        buf[written]     = (char)(0xF0 | ((codepoint >> 18) & 0x07));
                        buf[written + 1] = (char)(0x80 | ((codepoint >> 12) & 0x3F));
                        buf[written + 2] = (char)(0x80 | ((codepoint >>  6) & 0x3F));
                        buf[written + 3] = (char)(0x80 | ( codepoint        & 0x3F));
                    }
                    written += 4;
                }
                break;
            }
            default:
                return JERR_INVALID_ESCAPE;
            }
        } else {
            /* Normal character (must be printable ASCII or valid UTF‑8) */
            if ((unsigned char)*q < 0x20)
                return JERR_UNEXPECTED_CHAR; /* control character in string */
            if (written < (int)bufsz) buf[written] = *q;
            ++written; ++q;
        }
    }

    if (*q == '\0')
        return JERR_STRING_EOF; /* unterminated string */
    ++q; /* skip closing '"' */
    *p = q;
    if (len) *len = written;
    return JERR_OK;
}

/* ------------------------------------------------------------------ */
/* Helper: parse a JSON number into an int64_t.
 *
 * Returns 0 on success, non‑zero on error.
 * Rejects:
 *   • leading zeros (e.g. 00, 0.5, 1e02 is fine, but 01, 00)
 *   • fractional part (e.g. 1.2)
 *   • exponent (e.g. 1e+3)
 *   • values outside [-2^63, 2^63-1]
 */

static int parse_number(const char **p, int64_t *out)
{
    const char *q = *p;
    int neg = 0;
    int64_t val = 0;
    int digits = 0;

    if (*q == '-') {
        neg = 1;
        ++q;
    }

    if (*q == '\0')
        return JERR_END_OF_INPUT;

    /* At least one digit is required */
    if (*q < '0' || *q > '9')
        return JERR_UNEXPECTED_CHAR;

    /* Reject leading zeros */
    if (q[0] == '0' && (q[1] >= '0' && q[1] <= '9'))
        return JERR_NUMBER_LEADING_ZEROS;

    /* Parse digits while watching for overflow */
    while (*q >= '0' && *q <= '9') {
        int digit = *q - '0';
        /* Check overflow before multiplication:
         * if val > (INT64_MAX - digit) / 10 → overflow */
        if (val > (INT64_MAX - digit) / 10)
            return JERR_NUMBER_OVERFLOW;
        val = val * 10 + digit;
        ++digits;
        ++q;
    }

    if (digits == 0)
        return JERR_UNEXPECTED_CHAR;

    /* Any fractional part or exponent is an error */
    if (*q == '.' || *q == 'e' || *q == 'E')
        return JERR_NUMBER_FRACTIONAL;

    /* Apply sign */
    if (neg) {
        if (val > 0 && val > ((int64_t)0 - (int64_t)INT64_MIN) / 2)
            return JERR_NUMBER_OVERFLOW;
        val = -val;
    }

    *p = q;
    *out = val;
    return JERR_OK;
}

/* ------------------------------------------------------------------ */
/* Helper: parse a JSON value (number, string, literal, object, array)
 *   On entry *p points to the first non‑space character of the value.
 *   On exit  *p points to the first character after the value (',' ']' '}' etc.)
 */

static int parse_value(const char **p, int64_t *out)
{
    const char *q = skip_ws(*p);
    if (*q == '\0')
        return JERR_END_OF_INPUT;

    if (*q == '"') {
        /* String – we do not need the content, just skip it */
        char scratch[256];
        int dummy;
        int err = parse_string(&q, scratch, sizeof scratch, &dummy);
        if (err) return err;
        *p = q;
        return JERR_TYPE_MISMATCH; /* we need an integer, not a string */
    }

    if (*q == '{') {
        ++q;
        q = skip_ws(q);
        if (*q == '}') { ++q; *p = q; return JERR_TYPE_MISMATCH; }
        for (;;) {
            int err;
            char key[256];
            int keylen;
            err = parse_string(&q, key, sizeof key, &keylen);
            if (err) return err;
            q = skip_ws(q);
            if (*q != ':') return JERR_UNEXPECTED_CHAR;
            ++q;
            err = parse_value(&q, out);
            if (err == JERR_TYPE_MISMATCH) {
                /* value was not an integer – skip it and keep searching */
                /* out is already set to the first integer we found,
                 * which is wrong – we need to reset it. */
                /* Actually we should not have set out yet.
                 * The caller will only use out if we return JERR_OK.
                 * So we can safely ignore TYPE_MISMATCH here. */
            }
            q = skip_ws(q);
            if (*q == ',') { ++q; continue; }
            if (*q == '}') { ++q; *p = q; return JERR_TYPE_MISMATCH; }
            return JERR_UNEXPECTED_CHAR;
        }
    }

    if (*q == '[') {
        ++q;
        q = skip_ws(q);
        if (*q == ']') { ++q; *p = q; return JERR_TYPE_MISMATCH; }
        for (;;) {
            int err = parse_value(&q, out);
            if (err == JERR_TYPE_MISMATCH) {
                /* not an integer – skip it */
            }
            q = skip_ws(q);
            if (*q == ',') { ++q; continue; }
            if (*q == ']') { ++q; *p = q; return JERR_TYPE_MISMATCH; }
            return JERR_UNEXPECTED_CHAR;
        }
    }

    if (*q == 't')
        return parse_literal(&q, "true") ? JERR_UNEXPECTED_CHAR : JERR_TYPE_MISMATCH;
    if (*q == 'f')
        return parse_literal(&q, "false") ? JERR_UNEXPECTED_CHAR : JERR_TYPE_MISMATCH;
    if (*q == 'n')
        return parse_literal(&q, "null") ? JERR_UNEXPECTED_CHAR : JERR_TYPE_MISMATCH;

    /* Must be a number */
    return parse_number(&q, out);
}

/* ------------------------------------------------------------------ */
/* Helper: navigate the JSON according to a path.
 *
 * Path grammar (simplified):
 *   path  → ( '.' NAME | '[' INDEX ']' )*
 *   NAME  → [a‑zA‑Z_][a‑zA‑Z0‑9_]*
 *   INDEX → [0‑9]+
 *
 * An empty path means "return the root value".
 */

static int follow_path(const char *json, const char *path, int64_t *out)
{
    const char *p = json;
    const char *path_p = path;
    int64_t dummy; /* used when we only need to skip a value */
    int64_t *target = out;

    /* If the path is empty, we evaluate the root value */
    if (*path_p == '\0') {
        p = skip_ws(p);
        return parse_value(&p, out);
    }

    /* Otherwise walk the path token by token */
    while (1) {
        /* Expect a separator: either '.' or '[' */
        if (*path_p == '.') {
            ++path_p; /* skip '.' */
        } else if (*path_p == '[') {
            /* array index follows */
            ++path_p; /* skip '[' */
            if (*path_p < '0' || *path_p > '9')
                return JERR_PATH_MALFORMED;
            unsigned long idx = 0;
            while (*path_p >= '0' && *path_p <= '9') {
                idx = idx * 10 + (unsigned long)(*path_p - '0');
                ++path_p;
            }
            if (*path_p != ']')
                return JERR_PATH_MALFORMED;
            ++path_p; /* skip ']' */

            /* Skip to the beginning of the array in JSON */
            p = skip_ws(p);
            if (*p != '[')
                return JERR_TYPE_MISMATCH; /* not an array */
            ++p;
            p = skip_ws(p);
            if (*p == ']')
                return JERR_PATH_NOT_FOUND; /* empty array */

            /* Walk idx elements */
            for (;;) {
                int err;
                if (idx == 0) {
                    err = parse_value(&p, target);
                    if (err == JERR_TYPE_MISMATCH) {
                        /* The value we landed on is not an integer.
                         * We must still consume it so we can continue
                         * parsing the JSON, but we must NOT return it. */
                        dummy = 0;
                        target = &dummy;
                        err = parse_value(&p, target);
                        target = out; /* restore */
                    }
                    if (err) return err;
                    break;
                }
                /* Skip this element */
                err = parse_value(&p, &dummy);
                if (err) return err;
                p = skip_ws(p);
                if (*p == ',') { ++p; continue; }
                if (*p == ']') return JERR_PATH_NOT_FOUND;
                return JERR_UNEXPECTED_CHAR;
            }
        } else if (*path_p != '\0') {
            /* Implicit '.' before a name segment */
            /* (handled by falling through to NAME parsing) */
        } else {
            /* End of path – evaluate the current value */
            p = skip_ws(p);
            return parse_value(&p, out);
        }

        /* At this point we need a member name */
        if (*path_p == '\0') {
            /* Path ends after a separator – evaluate the value */
            p = skip_ws(p);
            return parse_value(&p, out);
        }

        /* Expect a member name */
        if (!isalpha((unsigned char)*path_p) && *path_p != '_')
            return JERR_PATH_MALFORMED;

        /* Collect the member name from the path */
        char name[64];
        size_t namelen = 0;
        while (isalnum((unsigned char)*path_p) || *path_p == '_') {
            if (namelen + 1 >= sizeof name)
                return JERR_PATH_MALFORMED;
            name[namelen++] = *path_p;
            ++path_p;
        }
        name[namelen] = '\0';

        /* Skip to the beginning of the object in JSON */
        p = skip_ws(p);
        if (*p != '{')
            return JERR_TYPE_MISMATCH; /* not an object */
        ++p;
        p = skip_ws(p);
        if (*p == '}')
            return JERR_PATH_NOT_FOUND; /* empty object */

        /* Walk the object's members */
        for (;;) {
            char key[64];
            int keylen;
            int err = parse_string(&p, key, sizeof key, &keylen);
            if (err) return err;
            p = skip_ws(p);
            if (*p != ':')
                return JERR_UNEXPECTED_CHAR;
            ++p;

            if (keylen == (int)namelen &&
                memcmp(key, name, namelen) == 0) {
                /* Found the key – parse its value */
                p = skip_ws(p);
                err = parse_value(&p, target);
                if (err == JERR_TYPE_MISMATCH) {
                    /* The value is not an integer.
                     * Consume it with a dummy target. */
                    dummy = 0;
                    target = &dummy;
                    err = parse_value(&p, target);
                    target = out;
                }
                if (err) return err;
                break;
            } else {
                /* Skip this value */
                err = parse_value(&p, &dummy);
                if (err) return err;
                p = skip_ws(p);
                if (*p == ',') { ++p; continue; }
                if (*p == '}') return JERR_PATH_NOT_FOUND;
                return JERR_UNEXPECTED_CHAR;
            }
        }
    }
}

