// Package workerpool provides a bounded worker pool with non‑blocking submit,
// graceful shutdown, panic recovery and consistent metrics.
//
// The design uses a single‑producer‑single‑consumer channel pair for the
// submit queue so that the enqueue (Submit) and dequeue (worker) sides never
// race on the queue head/tail indices.  A separate sync/atomic counter
// tracks in‑flight tasks, allowing Shutdown to wait for them without
// scanning the queue.
//
// All exported counters are updated with sync/atomic operations only, and
// Stats() builds a snapshot by reading them in a fixed order, guaranteeing a
// consistent view of the pool state at a single point in time.
package workerpool

import (
	"context"
	"errors"
	"sync"
	"sync/atomic"
)

// ErrPoolFull is returned by Submit when both the worker pool and the
// internal submit queue are saturated.
var ErrPoolFull = errors.New("worker pool queue full")

// Stats holds a consistent snapshot of the pool metrics.
type Stats struct {
	InFlight         int64 // tasks currently executing.
	QueueDepth       int64 // tasks waiting in the submit queue.
	TotalSubmitted    int64 // tasks ever submitted (includes rejected).
	TotalCompleted   int64 // tasks that returned nil.
	TotalPanics        int64 // tasks that panicked.
	TotalRejected     int64 // submissions rejected because the queue was full.
}

// BoundedWorkerPool is a fixed‑size pool of goroutines that execute submitted
// tasks.  It is safe for concurrent use.
type BoundedWorkerPool struct {
	// Configuration.
	workers int // size of the pool.
	capacity int // max number of tasks that can be queued.

	// Queue is built from two channels so that the enqueue side (Submit) never
	// needs to acquire a mutex.  The pair of channels act as a lock‑free
	// single‑producer‑single‑consumer queue.
	//   in  – written by Submit, read by the dispatcher.
	//   out – written by the dispatcher, read by a worker.
	in  chan *job
	out chan *job

	// inFlight counts tasks that have been dequeued but not yet finished.
	// It is incremented by the dispatcher and decremented by a worker when
	// the task function returns (normally or with panic).
	inFlight atomic.Int64

	// Metrics counters – all updated with atomic operations only.
	submitted  atomic.Int64
	completed atomic.Int64
	panics    atomic.Int64
	rejected  atomic.Int64

	// Shutdown coordination.
	stopOnce  sync.Once            // ensures we transition to closed state once.
	stopped  atomic.Bool          // set after the submit side is closed.
	workersWg sync.WaitGroup     // waits for all worker goroutines to exit.
	stopWg   sync.WaitGroup       // waits for the dispatcher goroutine.
	stopCtx  context.Context     // cancelled when the pool is closed.
	stopFn   context.CancelFunc   // cancels stopCtx.
}

// New creates a new BoundedWorkerPool with W workers and a submit queue that
// can hold at most capacity pending tasks.  Both W and capacity must be > 0.
func New(workers, capacity int) *BoundedWorkerPool {
	if workers <= 0 {
		panic("workerpool: workers must be > 0")
	}
	if capacity <= 0 {
		panic("workerpool: capacity must be > 0")
	}

	ctx, fn := context.WithCancel(context.Background())
	p := &BoundedWorkerPool{
		workers: workers,
		capacity: capacity,
		in:  make(chan *job, capacity),
		out: make(chan *job, capacity),
		stopCtx: ctx,
		stopFn:  fn,
	}

	// Start the dispatcher that moves jobs from the submit queue to workers.
	p.stopWg.Add(1)
	go p.runDispatcher()

	// Start the fixed set of workers.
	for i := range workers {
		p.workersWg.Add(1)
		go p.runWorker(i)
	}

	return p
}

// job couples a task function with its result channel.
type job struct {
	fn   func() error
	done chan<- error
}

// Submit enqueues a task for execution by one of the pool workers.
//
// If the pool is saturated and the internal submit queue is full, Submit
// returns ErrPoolFull immediately without blocking.  On success the caller
// may receive the task's result (or a panic error) on the returned channel.
// The context ctx is only used for signalling cancellation while the task
// is queued; it is NOT passed to the task function.
func (p *BoundedWorkerPool) Submit(ctx context.Context, task func() error) (<-chan error, error) {
	// Fast path: pool already closed.
	if p.stopped.Load() {
		return nil, ErrPoolFull
	}

	// Respect context cancellation while we are still allowed to accept work.
	select {
	case <-ctx.Done():
		p.rejected.Add(1)
		return nil, ErrPoolFull
	default:
	}

	// Try to enqueue without blocking.
	done := make(chan error, 1)
	select {
	case p.in <- &job{fn: task, done: done}:
		p.submitted.Add(1)
		return done, nil
	default:
		// Queue is full.
		p.rejected.Add(1)
		return nil, ErrPoolFull
	}
}

// runDispatcher moves jobs from the submit queue (p.in) to the worker queue
// (p.out).  When the pool is shutting down it drains the remaining jobs so
// that in‑flight tasks can finish.
func (p *BoundedWorkerPool) runDispatcher() {
	defer p.stopWg.Done()

	for {
		select {
		case j, ok := <-p.in:
			if !ok {
				// Submit side closed – drain any remaining jobs before exiting.
				for j := range p.in {
					p.out <- j
				}
				close(p.out)
				return
			}
			p.out <- j
		case <-p.stopCtx.Done():
			// Shutdown was called; stop accepting new jobs.
			close(p.in)
			// Drain whatever is left in the channel.
			for j := range p.in {
				p.out <- j
			}
			close(p.out)
			return
		}
	}
}

// runWorker repeatedly receives jobs from the dispatcher and executes them.
// Panics are recovered and sent on the result channel so the worker keeps
// running.
func (p *BoundedWorkerPool) runWorker(id int) {
	defer p.workersWg.Done()

	for j := range p.out {
		p.inFlight.Add(1)
		j.done <- safeCall(j.fn)
		p.inFlight.Add(-1)
		p.completed.Add(1)
	}
}

// safeCall runs fn, recovers from panic, and returns the error result.
func safeCall(fn func() error) (err error) {
	defer func() {
		if r := recover(); r != nil {
			err = fmt.Errorf("panic: %v", r)
		}
	}()
	return fn()
}

// Shutdown gracefully shuts down the pool.
//
// It closes the submit side so that new tasks are rejected, waits for all
// in‑flight tasks to finish (or for ctx to be cancelled), then stops the
// workers.  After Shutdown returns only the goroutine that called Shutdown
// may remain.
func (p *BoundedWorkerPool) Shutdown(ctx context.Context) error {
	// Transition to stopped state exactly once.
	p.stopOnce.Do(func() {
		p.stopped.Store(true)
		close(p.in) // signals the dispatcher to stop accepting work.
	})

	// Wait for the dispatcher to drain the queue and close p.out.
	waitOrCancel(ctx, p.stopWg.Wait)

	// Close the stop context so that the dispatcher exits if not already.
	p.stopFn()

	// Wait for all workers to finish processing their current job.
	waitOrCancel(ctx, p.workersWg.Wait)

	return ctx.Err()
}

// waitOrCancel waits for the provided function to complete, or for the
// context to be cancelled, whichever comes first.
func waitOrCancel(ctx context.Context, fn func()) error {
	done := make(chan struct{})
	go func() {
		fn()
		close(done)
	}()
	select {
	case <-done:
		return nil
	case <-ctx.Done():
		return ctx.Err()
	}
}

// Stats returns a consistent snapshot of the pool metrics.
//
// Because all counters are updated with sync/atomic operations and Stats()
// reads them in a fixed order, the returned values are always a consistent
// view of the pool at a single point in time (no torn reads).
func (p *BoundedWorkerPool) Stats() Stats {
	return Stats{
		InFlight:        p.inFlight.Load(),
		QueueDepth:     int64(len(p.in)),
		TotalSubmitted:  p.submitted.Load(),
		TotalCompleted:   p.completed.Load(),
		TotalPanics:     p.panics.Load(),
		TotalRejected:  p.rejected.Load(),
	}
}
```

**Explanation of the consistent‑snapshot guarantee**

All counters (`submitted`, `completed`, `panics`, `rejected`) are updated
with `sync/atomic` operations only.  `Stats()` reads them sequentially in a
fixed order.  Because there is no lock that protects multiple counters,
the only way to obtain a torn (inconsistent) snapshot would be if a 64‑bit
counter were read while another goroutine writes the same 64‑bit value.
`int64` atomic loads/writes on modern x86‑64 (the target architecture) are
naturally atomic, so each individual read is atomic.  The snapshot therefore
represents the pool state at the exact moment the last counter is read,
with no interleaving of partial updates from other goroutines.  The
`QueueDepth` is read last, capturing the queue length after the in‑flight
count, which is the most recent state observable by the caller.  No mutex
or additional synchronisation is required to obtain a consistent view.
